import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './src/App';

console.log("The Data Refinery starting up... Entry point: index.tsx");

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

try {
  const root = ReactDOM.createRoot(rootElement);
  root.render(
    <React.StrictMode>
      <App />
    </React.StrictMode>
  );
} catch (error) {
  console.error("Critical failure during React initialization:", error);
  rootElement.innerHTML = `
    <div style="padding: 20px; color: #ff4444; font-family: monospace; background: #1a1a1a; height: 100vh;">
      <h1>// CRITICAL_BOOT_FAILURE</h1>
      <p>The Data Refinery failed to initialize.</p>
      <pre style="background: #000; padding: 15px; border-radius: 4px;">${error instanceof Error ? error.message : String(error)}</pre>
      <button onclick="window.location.reload()" style="background: #333; color: #fff; border: 1px solid #555; padding: 10px 20px; cursor: pointer;">Retry Boot Sequence</button>
    </div>
  `;
}

